 * (string) to planned-points contribution, e.g.
 * {@code {"<uuid>":5,"<uuid>":3}}.
 */
@Entity
@Table(name = "rcdo_week_rollup")
public class RcdoWeekRollup {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

